/**
 * Feature catalog — hand-curated map of operator-facing pages and what they do.
 *
 * Two consumers:
 *   1. `get_current_screen_context` enriches its response with a `page` block
 *      so Henry knows what the user is currently looking at (not just the URL).
 *   2. `find_feature` lets Henry answer "where is X?" / "can I do X?" by
 *      searching this catalog.
 *
 * This is interim. Phase 2 replaces it with a `public.help_docs` corpus
 * generated by an operator-audience doc-writer agent (see kanban). When that
 * lands, `find_feature` switches to embedding search and this static list
 * is retired.
 *
 * Conventions:
 *   - `path` matches the dashboard route exactly (no trailing slash).
 *   - `summary` is one sentence describing what the operator does on this page.
 *   - `keywords` are alternate phrasings a user might say. Lowercase.
 *   - Only include pages an operator might ASK about. Skip purely transactional
 *     edit/new sub-pages unless they're a destination.
 */

export type FeatureEntry = {
  path: string;
  name: string;
  summary: string;
  keywords: string[];
};

