/**
 * Look up a feature by exact path, ignoring querystring/hash.
 * Returns null if the path isn't in the catalog or is a dynamic sub-route
 * we haven't catalogued.
 */
export function findFeatureByPath(path: string | null | undefined): FeatureEntry | null {
  if (!path) return null;
  const cleaned = path.split('?')[0]?.split('#')[0]?.replace(/\/$/, '') || '/';
  // Exact match first.
  const exact = FEATURE_CATALOG.find((f) => f.path === cleaned);
  if (exact) return exact;
  // Fall back to longest prefix (handles /projects/<id>, /jobs/<id>, etc.).
  const prefix = FEATURE_CATALOG.filter(
    (f) => cleaned.startsWith(`${f.path}/`) && f.path !== '/',
  ).sort((a, b) => b.path.length - a.path.length)[0];
  return prefix ?? null;
}

/**
 * Search the catalog for features matching a free-text query. Scores by
 * keyword/name/summary token overlap; cheap and good-enough for ~30 entries.
 */
export function searchFeatures(query: string, limit = 5): FeatureEntry[] {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  const tokens = q.split(/\s+/).filter(Boolean);

  const scored = FEATURE_CATALOG.map((f) => {
    const hay = `${f.name} ${f.summary} ${f.keywords.join(' ')}`.toLowerCase();
    let score = 0;
    for (const t of tokens) {
      if (hay.includes(t)) score += 1;
      if (f.keywords.some((k) => k === t)) score += 2;
      if (f.name.toLowerCase().includes(t)) score += 2;
    }
    return { f, score };
  })
    .filter((x) => x.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);

  return scored.map((x) => x.f);
}
